#include <stdio.h>
#include <unistd.h>
#include <getopt.h>
#include <stdlib.h>
#include <assert.h>
#include <cuda_runtime.h>

#include "common.h"

static int do_verify = 0;
int omp_num_threads = 40;

static struct option long_options[] = {
  {"input", 1, NULL, 'i'},
  {"size", 1, NULL, 's'},
  {"verify", 0, NULL, 'v'},
  {0,0,0,0}
};

#define BS 16

static inline void cuda_check(cudaError_t e, const char *msg) {
  if (e != cudaSuccess) {
    fprintf(stderr, "CUDA error at %s: %s\n", msg, cudaGetErrorString(e));
    exit(EXIT_FAILURE);
  }
}

__global__ void lud_diagonal_kernel(float *a, int size, int offset) {
  if (blockIdx.x == 0 && threadIdx.x == 0) {
    for (int i = 0; i < BS; i++) {
      for (int j = i; j < BS; j++) {
        for (int k = 0; k < i; k++) {
          a[(offset + i) * size + (offset + j)] =
              a[(offset + i) * size + (offset + j)] -
              a[(offset + i) * size + (offset + k)] * a[(offset + k) * size + (offset + j)];
        }
      }

      float temp = 1.f / a[(offset + i) * size + (offset + i)];
      for (int j = i + 1; j < BS; j++) {
        for (int k = 0; k < i; k++) {
          a[(offset + j) * size + (offset + i)] =
              a[(offset + j) * size + (offset + i)] -
              a[(offset + j) * size + (offset + k)] * a[(offset + k) * size + (offset + i)];
        }
        a[(offset + j) * size + (offset + i)] =
            a[(offset + j) * size + (offset + i)] * temp;
      }
    }
  }
}

__global__ void lud_perimeter_kernel(float *a, int size, int offset, int chunks_in_inter_row) {
  int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (chunk_idx >= chunks_in_inter_row) return;

  float temp[BS * BS];

  for (int i = 0; i < BS; i++) {
    for (int j = 0; j < BS; j++) {
      temp[i * BS + j] = a[(i + offset) * size + (offset + j)];
    }
  }

  int i_global = offset;
  int j_global = offset;

  j_global += BS * (chunk_idx + 1);
  for (int j = 0; j < BS; j++) {
    for (int i = 0; i < BS; i++) {
      float sum = 0.f;
      for (int k = 0; k < i; k++) {
        sum += temp[BS * i + k] * a[(i_global + k) * size + (j_global + j)];
      }
      int i_here = i_global + i;
      int j_here = j_global + j;
      a[i_here * size + j_here] = a[i_here * size + j_here] - sum;
    }
  }

  j_global = offset;
  i_global += BS * (chunk_idx + 1);
  for (int i = 0; i < BS; i++) {
    for (int j = 0; j < BS; j++) {
      float sum = 0.f;
      for (int k = 0; k < j; k++) {
        sum += a[(i_global + i) * size + (j_global + k)] * temp[BS * k + j];
      }
      int i_here = i_global + i;
      int j_here = j_global + j;
      a[i_here * size + j_here] =
          (a[i_here * size + j_here] - sum) / a[(offset + j) * size + (offset + j)];
    }
  }
}

__global__ void lud_internal_kernel(float *a, int size, int offset, int chunks_in_inter_row, int chunks_per_inter) {
  int chunk_idx = blockIdx.x * blockDim.x + threadIdx.x;
  if (chunk_idx >= chunks_per_inter) return;

  float temp_top[BS * BS];
  float temp_left[BS * BS];
  float sum[BS];

  for (int j = 0; j < BS; j++) sum[j] = 0.f;

  int i_global = offset + BS * (1 + chunk_idx / chunks_in_inter_row);
  int j_global = offset + BS * (1 + chunk_idx % chunks_in_inter_row);

  for (int i = 0; i < BS; i++) {
    for (int j = 0; j < BS; j++) {
      temp_top[i * BS + j]  = a[(i + offset) * size + (j + j_global)];
      temp_left[i * BS + j] = a[(i + i_global) * size + (offset + j)];
    }
  }

  for (int i = 0; i < BS; i++) {
    for (int k = 0; k < BS; k++) {
      for (int j = 0; j < BS; j++) {
        sum[j] += temp_left[BS * i + k] * temp_top[BS * k + j];
      }
    }
    for (int j = 0; j < BS; j++) {
      a[(i + i_global) * size + (j + j_global)] -= sum[j];
      sum[j] = 0.f;
    }
  }
}

void lud_omp(float *a, int size)
{
    int offset, chunk_idx, size_inter, chunks_in_inter_row, chunks_per_inter;
    (void)chunk_idx;

    printf("running OMP on host\n");

    float *d_a = NULL;
    size_t bytes = (size_t)size * (size_t)size * sizeof(float);
    cuda_check(cudaMalloc((void**)&d_a, bytes), "cudaMalloc");
    cuda_check(cudaMemcpy(d_a, a, bytes, cudaMemcpyHostToDevice), "cudaMemcpy H2D");

    for (offset = 0; offset < size - BS ; offset += BS)
    {
        lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);
        cuda_check(cudaGetLastError(), "lud_diagonal_kernel");
        cuda_check(cudaDeviceSynchronize(), "sync diagonal");

        size_inter = size - offset - BS;
        chunks_in_inter_row = size_inter / BS;

        if (chunks_in_inter_row > 0) {
          int threads = 128;
          int blocks = (chunks_in_inter_row + threads - 1) / threads;
          lud_perimeter_kernel<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row);
          cuda_check(cudaGetLastError(), "lud_perimeter_kernel");
          cuda_check(cudaDeviceSynchronize(), "sync perimeter");
        }

        chunks_per_inter = chunks_in_inter_row * chunks_in_inter_row;
        if (chunks_per_inter > 0) {
          int threads = 128;
          int blocks = (chunks_per_inter + threads - 1) / threads;
          lud_internal_kernel<<<blocks, threads>>>(d_a, size, offset, chunks_in_inter_row, chunks_per_inter);
          cuda_check(cudaGetLastError(), "lud_internal_kernel");
          cuda_check(cudaDeviceSynchronize(), "sync internal");
        }
    }

    lud_diagonal_kernel<<<1, 1>>>(d_a, size, offset);
    cuda_check(cudaGetLastError(), "final lud_diagonal_kernel");
    cuda_check(cudaDeviceSynchronize(), "sync final diagonal");

    cuda_check(cudaMemcpy(a, d_a, bytes, cudaMemcpyDeviceToHost), "cudaMemcpy D2H");
    cuda_check(cudaFree(d_a), "cudaFree");
}

int
main ( int argc, char *argv[] )
{
  int matrix_dim = 32;
  int opt, option_index=0;
  func_ret_t ret;
  const char *input_file = NULL;
  float *m, *mm;
  stopwatch sw;

  while ((opt = getopt_long(argc, argv, "::vs:n:i:",
                            long_options, &option_index)) != -1 ) {
    switch(opt){
    case 'i':
      input_file = optarg;
      break;
    case 'v':
      do_verify = 1;
      break;
    case 'n':
      omp_num_threads = atoi(optarg);
      break;
    case 's':
      matrix_dim = atoi(optarg);
      printf("Generate input matrix internally, size =%d\n", matrix_dim);
      break;
    case '?':
      fprintf(stderr, "invalid option\n");
      break;
    case ':':
      fprintf(stderr, "missing argument\n");
      break;
    default:
      fprintf(stderr, "Usage: %s [-v] [-s matrix_size|-i input_file]\n",
              argv[0]);
      exit(EXIT_FAILURE);
    }
  }

  if ( (optind < argc) || (optind == 1)) {
    fprintf(stderr, "Usage: %s [-v] [-n no. of threads] [-s matrix_size|-i input_file]\n", argv[0]);
    exit(EXIT_FAILURE);
  }

  if (input_file) {
    printf("Reading matrix from file %s\n", input_file);
    ret = create_matrix_from_file(&m, input_file, &matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix from file %s\n", input_file);
      exit(EXIT_FAILURE);
    }
  }
  else if (matrix_dim) {
    printf("Creating matrix internally size=%d\n", matrix_dim);
    ret = create_matrix(&m, matrix_dim);
    if (ret != RET_SUCCESS) {
      m = NULL;
      fprintf(stderr, "error create matrix internally size=%d\n", matrix_dim);
      exit(EXIT_FAILURE);
    }
  }

  else {
    printf("No input file specified!\n");
    exit(EXIT_FAILURE);
  }

  if (do_verify){
    printf("Before LUD\n");
    matrix_duplicate(m, &mm, matrix_dim);
  }

  stopwatch_start(&sw);
  lud_omp(m, matrix_dim);
  stopwatch_stop(&sw);
  printf("Time consumed(ms): %lf\n", 1000*get_interval_by_sec(&sw));

  if (do_verify){
    printf("After LUD\n");
    printf(">>>Verify<<<<\n");
    lud_verify(mm, m, matrix_dim);
    free(mm);
  }

  free(m);

  return EXIT_SUCCESS;
}
